Create Lead.code:
// Create a CRM lead in Odoo.
create(
  // Odoo model name.
  'crm.lead',
  // Field values.
  {
    name:        $.data.opportunityName,
    contact_name: $.data.contactName,
    email_from:  $.data.email,
    phone:       $.data.phone,
  }
);

Create/Update Module Entry.code:
// Create (or update) a record in any Odoo model.
// To create:
create('res.partner', {
  name:  $.data.name,
  email: $.data.email,
});

// To update an existing record:
// update('res.partner', $.data.partnerId, { email: $.data.email });

Relate Module Entry.code:
// Set a many2one relation field by writing the related id.
update(
  // Model owning the relation field.
  'crm.lead',
  // Record id on that model.
  $.data.leadId,
  // Many2one fields take just the related id.
  { partner_id: $.data.partnerId }
);

Find Module Entry.code:
// Search a model with an Odoo domain filter and pull a single record back.
searchReadRecord(
  'res.partner',
  // Odoo domain: array of triples or logical operators.
  [['email', '=', $.data.email]],
  // Fields to return.
  ['id', 'name', 'email']
);

Find Multiple Module Entries.code:
// Search a model and return many records.
searchReadRecord(
  'crm.lead',
  // Domain — leads created in the last 30 days.
  [['create_date', '>=', '2026-04-01']],
  ['id', 'name', 'email_from', 'stage_id']
);
